import { Reporter, TestCase, TestResult } from '@playwright/test/reporter';

class TestRailReporter implements Reporter {
  async onTestEnd(test: TestCase, result: TestResult) {
    const testId = this.extractTestId(test.title);
    if (!testId) return;

    await fetch('https://testrail.com/api/add_result', {
      method: 'POST',
      headers: { 'Authorization': `Bearer ${process.env.TESTRAIL_TOKEN}` },
      body: JSON.stringify({
        test_id: testId,
        status_id: result.status === 'passed' ? 1 : 5,
        comment: result.error?.message
      })
    });
  }

  extractTestId(title: string) {
    const match = title.match(/\[C(\d+)\]/);
    return match ? match[1] : null;
  }
}
